import{c as o,Q as a,j as r,m as e}from"./chunks/framework.DpF7k2f3.js";const _=JSON.parse('{"title":"제3장 당신의 입문 로드맵","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part1-cognition/chapter3.md","filePath":"ko/part1-cognition/chapter3.md"}'),p={name:"ko/part1-cognition/chapter3.md"};function n(i,t,s,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="제3장-당신의-입문-로드맵" tabindex="-1">제3장 당신의 입문 로드맵 <a class="header-anchor" href="#제3장-당신의-입문-로드맵" aria-label="Permalink to &quot;제3장 당신의 입문 로드맵&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>앞의 두 챕터에서 &quot;입문할 수 있는가&quot;와 &quot;지금 입문해야 하는가&quot; 문제를 해결했습니다. 이 챕터는 인식편의 마무�로, 당신에게 <strong>그대로 따라갈 수 있는 로드맵</strong>을 드리겠습니다.</p><p>이 챕터를 읽고 나면 알게 될 것들:</p><ul><li>당신이 어떤 유형의 입문자인지(백엔드/프론트엔드/초보/학생), 그리고 당신만의 전략</li><li>8주 입문 스프린트 계획, 매주 무엇을 해야 하는지精确</li><li>6개월 심화 진화 계획, &quot;일을 할 수 있다&quot;에서 &quot;站稳脚跟&quot;로</li><li>학습 자료 선택 방법,哪些值得花钱,哪些免费够用</li></ul><p>이 챕터를 보면,書を閉じて、コンピュータを開いて、执行を開始する必要があります.</p><hr><h2 id="_3-1-네-가지-유형의-입문자-프로파일과-각자의-전략" tabindex="-1">3.1 네 가지 유형의 입문자 프로파일과 각자의 전략 <a class="header-anchor" href="#_3-1-네-가지-유형의-입문자-프로파일과-각자의-전략" aria-label="Permalink to &quot;3.1 네 가지 유형의 입문자 프로파일과 각자의 전략&quot;">​</a></h2><p>로드맵을 그리기 전에, 먼저 질문합니다: <strong>당신은 누구입니까?</strong></p><p>AI 분야 입문에는 표준 답이 없습니다. 출발점이 다르면, 최적의 경로도 다릅니다.</p><p>저는 입문자를 4가지 유형으로 나누며, 각 유형마다 자신만의 장점과 함정이 있습니다. 유형을 파악하고 당신에게 맞는 전략을 찾으세요.</p><hr><h3 id="유형-1-백엔드-→-ai-개발-전직" tabindex="-1">유형 1: 백엔드 → AI 개발 전직 <a class="header-anchor" href="#유형-1-백엔드-→-ai-개발-전직" aria-label="Permalink to &quot;유형 1: 백엔드 → AI 개발 전직&quot;">​</a></h3><p><strong>당신은 누구인가</strong></p><p>1-5년 경력의 백엔드 개발자로, Java, Go, Python都有可能, API를 작성하고 서비스를 구축하며 데이터베이스와 교차해 왔으며, 코드 작성은 문제가 아닙니다, 문제는 &quot;AI那边的代码怎么写&quot;.</p><p><strong>당신의 장점</strong></p><p>최대의 장점은 <strong>엔지니어링 능력</strong>입니다. 많은 사람들이 AI로 전환하면 엔지니어링 능력을 포기해야 한다고 생각하지만, 사실 정반대입니다 - 2026년에 가장 희귀한 인재는 AI 모델을 안정적으로 운영할 수 있는 사람입니다.</p><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter3.html">中文版阅读</a></p></blockquote>',19)])])}const d=o(p,[["render",n]]);export{_ as __pageData,d as default};
